package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.internal.bind.TreeTypeAdapter;
import com.google.gson.internal.bind.TypeAdapters;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

import java.lang.reflect.Field;
import java.util.List;

public class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  public void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  public void registerTypeHierarchyAdapter_withJsonSerializer_addsToHierarchyFactories() throws Exception {
    Class<?> baseType = String.class;
    JsonSerializer<String> serializer = mock(JsonSerializer.class);

    try (MockedStatic<TreeTypeAdapter> treeTypeAdapterMockedStatic = Mockito.mockStatic(TreeTypeAdapter.class)) {
      TypeAdapterFactory mockedFactory = mock(TypeAdapterFactory.class);
      treeTypeAdapterMockedStatic.when(() -> TreeTypeAdapter.newTypeHierarchyFactory(baseType, serializer))
          .thenReturn(mockedFactory);

      GsonBuilder returned = gsonBuilder.registerTypeHierarchyAdapter(baseType, serializer);
      assertSame(gsonBuilder, returned);

      Field hierarchyFactoriesField = GsonBuilder.class.getDeclaredField("hierarchyFactories");
      hierarchyFactoriesField.setAccessible(true);
      List<TypeAdapterFactory> hierarchyFactories = (List<TypeAdapterFactory>) hierarchyFactoriesField.get(gsonBuilder);

      assertTrue(hierarchyFactories.contains(mockedFactory));

      // factories list should be empty
      Field factoriesField = GsonBuilder.class.getDeclaredField("factories");
      factoriesField.setAccessible(true);
      List<TypeAdapterFactory> factories = (List<TypeAdapterFactory>) factoriesField.get(gsonBuilder);
      assertTrue(factories.isEmpty());
    }
  }

  @Test
  public void registerTypeHierarchyAdapter_withJsonDeserializer_addsToHierarchyFactories() throws Exception {
    Class<?> baseType = Integer.class;
    JsonDeserializer<Integer> deserializer = mock(JsonDeserializer.class);

    try (MockedStatic<TreeTypeAdapter> treeTypeAdapterMockedStatic = Mockito.mockStatic(TreeTypeAdapter.class)) {
      TypeAdapterFactory mockedFactory = mock(TypeAdapterFactory.class);
      treeTypeAdapterMockedStatic.when(() -> TreeTypeAdapter.newTypeHierarchyFactory(baseType, deserializer))
          .thenReturn(mockedFactory);

      GsonBuilder returned = gsonBuilder.registerTypeHierarchyAdapter(baseType, deserializer);
      assertSame(gsonBuilder, returned);

      Field hierarchyFactoriesField = GsonBuilder.class.getDeclaredField("hierarchyFactories");
      hierarchyFactoriesField.setAccessible(true);
      List<TypeAdapterFactory> hierarchyFactories = (List<TypeAdapterFactory>) hierarchyFactoriesField.get(gsonBuilder);

      assertTrue(hierarchyFactories.contains(mockedFactory));

      Field factoriesField = GsonBuilder.class.getDeclaredField("factories");
      factoriesField.setAccessible(true);
      List<TypeAdapterFactory> factories = (List<TypeAdapterFactory>) factoriesField.get(gsonBuilder);
      assertTrue(factories.isEmpty());
    }
  }

  @Test
  public void registerTypeHierarchyAdapter_withTypeAdapter_addsToFactories() throws Exception {
    Class<?> baseType = Double.class;
    @SuppressWarnings("unchecked")
    TypeAdapter<Double> typeAdapter = mock(TypeAdapter.class);

    try (MockedStatic<TypeAdapters> typeAdaptersMockedStatic = Mockito.mockStatic(TypeAdapters.class)) {
      TypeAdapterFactory mockedFactory = mock(TypeAdapterFactory.class);
      typeAdaptersMockedStatic.when(() -> TypeAdapters.newTypeHierarchyFactory(baseType, typeAdapter))
          .thenReturn(mockedFactory);

      GsonBuilder returned = gsonBuilder.registerTypeHierarchyAdapter(baseType, typeAdapter);
      assertSame(gsonBuilder, returned);

      Field factoriesField = GsonBuilder.class.getDeclaredField("factories");
      factoriesField.setAccessible(true);
      List<TypeAdapterFactory> factories = (List<TypeAdapterFactory>) factoriesField.get(gsonBuilder);

      assertTrue(factories.contains(mockedFactory));

      Field hierarchyFactoriesField = GsonBuilder.class.getDeclaredField("hierarchyFactories");
      hierarchyFactoriesField.setAccessible(true);
      List<TypeAdapterFactory> hierarchyFactories = (List<TypeAdapterFactory>) hierarchyFactoriesField.get(gsonBuilder);
      assertTrue(hierarchyFactories.isEmpty());
    }
  }

  @Test
  public void registerTypeHierarchyAdapter_withJsonSerializerAndTypeAdapter_addsToBothFactories() throws Exception {
    Class<?> baseType = Number.class;

    JsonSerializer<Number> serializer = mock(JsonSerializer.class);
    @SuppressWarnings("unchecked")
    TypeAdapter<Number> typeAdapter = mock(TypeAdapter.class);

    // Create a proxy object that implements both interfaces
    Object combinedAdapter = new Object() implements JsonSerializer<Number>, TypeAdapter<Number> {
      @Override
      public JsonElement serialize(Number src, java.lang.reflect.Type typeOfSrc, JsonSerializationContext context) {
        return null;
      }
    };

    // But since we cannot instantiate anonymous class implementing both easily, 
    // we will test by calling separately, as the method expects one object.

    // So instead, test with JsonSerializer instance which is also a TypeAdapter via mocking.

    // We create a mock that implements both interfaces
    Object adapter = mock(Object.class, withSettings().extraInterfaces(JsonSerializer.class, TypeAdapter.class));

    try (MockedStatic<TreeTypeAdapter> treeTypeAdapterMockedStatic = Mockito.mockStatic(TreeTypeAdapter.class);
         MockedStatic<TypeAdapters> typeAdaptersMockedStatic = Mockito.mockStatic(TypeAdapters.class)) {
      TypeAdapterFactory hierarchyFactory = mock(TypeAdapterFactory.class);
      TypeAdapterFactory factory = mock(TypeAdapterFactory.class);

      treeTypeAdapterMockedStatic.when(() -> TreeTypeAdapter.newTypeHierarchyFactory(baseType, adapter))
          .thenReturn(hierarchyFactory);
      typeAdaptersMockedStatic.when(() -> TypeAdapters.newTypeHierarchyFactory(baseType, (TypeAdapter<?>) adapter))
          .thenReturn(factory);

      GsonBuilder returned = gsonBuilder.registerTypeHierarchyAdapter(baseType, adapter);
      assertSame(gsonBuilder, returned);

      Field hierarchyFactoriesField = GsonBuilder.class.getDeclaredField("hierarchyFactories");
      hierarchyFactoriesField.setAccessible(true);
      List<TypeAdapterFactory> hierarchyFactories = (List<TypeAdapterFactory>) hierarchyFactoriesField.get(gsonBuilder);
      assertTrue(hierarchyFactories.contains(hierarchyFactory));

      Field factoriesField = GsonBuilder.class.getDeclaredField("factories");
      factoriesField.setAccessible(true);
      List<TypeAdapterFactory> factories = (List<TypeAdapterFactory>) factoriesField.get(gsonBuilder);
      assertTrue(factories.contains(factory));
    }
  }

  @Test
  public void registerTypeHierarchyAdapter_nullBaseType_throwsNullPointerException() {
    assertThrows(NullPointerException.class, () -> gsonBuilder.registerTypeHierarchyAdapter(null, mock(JsonSerializer.class)));
  }

  @Test
  public void registerTypeHierarchyAdapter_invalidTypeAdapter_throwsIllegalArgumentException() {
    Class<?> baseType = String.class;
    Object invalidAdapter = new Object();

    IllegalArgumentException exception = assertThrows(IllegalArgumentException.class,
        () -> gsonBuilder.registerTypeHierarchyAdapter(baseType, invalidAdapter));
    assertTrue(exception.getMessage().contains("Expected"));
  }
}
